import React from 'react';
import { Box, Card, CardContent, Stack, Typography } from '@mui/material';

export interface PageContainerProps {
    /** Leading icon shown next to the title (defaults to nothing if omitted). */
    icon?: React.ReactNode;
    /** Page title rendered as bold h5. */
    title?: string;
    /** Optional supporting copy under the title. */
    subtitle?: string;
    /** Trailing action(s) rendered on the right of the header (e.g. Edit button). */
    action?: React.ReactNode;
    /** Max content width in px. Defaults to 720 (matches the Security pages). */
    maxWidth?: number | string;
    /** Page body. */
    children: React.ReactNode;
}

/**
 * Standard page wrapper used across the app: centered max-width container with an
 * optional header card (icon + bold title + subtitle + trailing action). Pages that
 * supply only `children` get just the centered container; pages that supply `title`
 * additionally render the header card.
 *
 * Usage:
 * ```tsx
 * <PageContainer icon={<PersonIcon color="primary" />} title="My profile"
 *                subtitle="..." action={<Button>Edit</Button>}>
 *     ...page body...
 * </PageContainer>
 * ```
 */
export const PageContainer: React.FC<PageContainerProps> = ({
    icon,
    title,
    subtitle,
    action,
    maxWidth = 720,
    children,
}) => {
    const showHeader = !!(title || subtitle || icon || action);
    return (
        <Box sx={{ maxWidth, mx: 'auto', px: { xs: 1, sm: 2 } }}>
            {showHeader && (
                <Card variant="outlined" sx={{ borderRadius: 2, mb: 2 }}>
                    <CardContent sx={{ '&:last-child': { pb: 2 } }}>
                        <Stack
                            direction="row"
                            spacing={1.5}
                            sx={{ alignItems: 'flex-start', justifyContent: 'space-between' }}
                        >
                            <Box sx={{ minWidth: 0 }}>
                                {(title || icon) && (
                                    <Stack
                                        direction="row"
                                        spacing={1.5}
                                        sx={{ alignItems: 'center', mb: subtitle ? 0.5 : 0 }}
                                    >
                                        {icon}
                                        {title && (
                                            <Typography variant="h5" sx={{ fontWeight: 700 }}>
                                                {title}
                                            </Typography>
                                        )}
                                    </Stack>
                                )}
                                {subtitle && (
                                    <Typography variant="body2" color="text.secondary">
                                        {subtitle}
                                    </Typography>
                                )}
                            </Box>
                            {action && <Box sx={{ flexShrink: 0 }}>{action}</Box>}
                        </Stack>
                    </CardContent>
                </Card>
            )}
            {children}
        </Box>
    );
};
